31	// FinalizeDurableAttemptAudit appends the per-attempt metrics row, when the
32	// report carries an attempt_id, and commits any DDx-managed durable audit files
33	// that changed during the attempt.
34	func FinalizeDurableAttemptAudit(projectRoot string, store durableAuditBeadReader, report ExecuteBeadReport) error {
35		if strings.TrimSpace(projectRoot) == "" {
36			projectRoot = report.ProjectRoot
37		}
38		if strings.TrimSpace(projectRoot) == "" {
39			return fmt.Errorf("finalize durable audit: project root required")
40		}
41		if strings.TrimSpace(report.AttemptID) != "" {
42			if err := attemptmetrics.AppendRow(projectRoot, buildAttemptMetricsRow(store, report, time.Now().UTC())); err != nil {
43				return fmt.Errorf("append attempt metrics: %w", err)
44			}
45		}
46		if err := CommitDurableAuditOutputs(projectRoot, report.AttemptID); err != nil {
47			return fmt.Errorf("commit durable audit outputs: %w", err)
48		}
49		return nil
50	}
