52	// CommitDurableAuditOutputs stages and commits the DDx-managed durable audit
53	// paths when they are dirty. The commit is serialized through the main git lock
54	// so concurrent workers cannot interleave tracker and audit commits.
55	func CommitDurableAuditOutputs(projectRoot, attemptID string) error {
56		return withTrackerLock(projectRoot, "durable_audit", func() error {
57			return commitDurableAuditOutputsLocked(projectRoot, attemptID)
58		})
59	}
