61	func buildAttemptMetricsRow(store durableAuditBeadReader, report ExecuteBeadReport, finishedAt time.Time) attemptmetrics.AttemptRow {
62		specID := ""
63		if report.BeadID != "" && store != nil {
64			if b, err := store.Get(context.Background(), report.BeadID); err == nil && b != nil {
65				specID, _ = b.Extra["spec-id"].(string)
66			}
67		}
68		tsEnd := attemptmetrics.Rfc3339(finishedAt)
69		tsStart := ""
70		if report.DurationMS > 0 {
71			start := finishedAt.Add(-time.Duration(report.DurationMS) * time.Millisecond)
72			tsStart = attemptmetrics.Rfc3339(start)
73		}
74		return attemptmetrics.AttemptRow{
75			SchemaVersion: attemptmetrics.SchemaVersion,
76			AttemptID:     report.AttemptID,
77			BeadID:        report.BeadID,
78			SessionID:     report.SessionID,
79			TSStart:       tsStart,
80			TSEnd:         tsEnd,
81			Model:         report.Model,
82			Harness:       report.Harness,
83			Profile:       report.RequestedProfile,
84			Provider:      report.Provider,
85			SpecID:        specID,
86			Outcome:       report.Status,
87			CostUSD:       report.CostUSD,
88			DurationMS:    int(report.DurationMS),
89			ReviewVerdict: report.ReviewVerdict,
90		}
91	}
