93	func commitDurableAuditOutputsLocked(projectRoot, attemptID string) error {
94		gitDir, managedPathspecs := ddxStateGitScope(projectRoot, trackerpaths.ManagedPathspecs()...)
95	
96		out, err := runDurableAuditGit(gitDir, "rev-parse", "--is-inside-work-tree")
97		if err != nil || strings.TrimSpace(string(out)) != "true" {
98			return nil
99		}
100	
101		statusArgs := []string{"status", "--short", "--untracked-files=all", "--"}
102		statusArgs = append(statusArgs, managedPathspecs...)
103		statusOut, err := runDurableAuditGit(gitDir, statusArgs...)
104		if err != nil {
105			return fmt.Errorf("checking durable audit status: %w", err)
106		}
107		dirtyPaths := dirtyDurableAuditPaths(string(statusOut))
108		if len(dirtyPaths) == 0 {
109			return nil
110		}
111	
112		addArgs := []string{"add", "-A", "--"}
113		addArgs = append(addArgs, dirtyPaths...)
114		addOut, err := runDurableAuditGitWithIndexLockRecovery(gitDir, addArgs...)
115		if err != nil {
116			return fmt.Errorf("staging durable audit outputs: %s: %w", strings.TrimSpace(string(addOut)), err)
117		}
118	
119		cachedArgs := []string{"diff", "--cached", "--"}
120		cachedArgs = append(cachedArgs, dirtyPaths...)
121		if cached, err := runDurableAuditGit(gitDir, cachedArgs...); err == nil && strings.TrimSpace(string(cached)) == "" {
122			return nil
123		}
124	
125		commitArgs := []string{"commit", "--no-verify", "--only", "-m", durableAuditCommitMessage(attemptID), "--"}
126		commitArgs = append(commitArgs, dirtyPaths...)
127		commitArgs = ddxStateCommitArgs(projectRoot, gitDir, commitArgs...)
128		commitOut, err := runDurableAuditGitWithIndexLockRecovery(gitDir, commitArgs...)
129		if err != nil {
130			return fmt.Errorf("committing durable audit outputs: %s: %w", strings.TrimSpace(string(commitOut)), err)
131		}
132		return nil
133	}
