135	func runDurableAuditGit(gitDir string, args ...string) ([]byte, error) {
136		ctx, cancel := durableAuditCommandContext()
137		defer cancel()
138		return durableAuditGitRunner(ctx, gitDir, args...)
139	}
140	
141	func runDurableAuditGitWithIndexLockRecovery(gitDir string, args ...string) ([]byte, error) {
142		var out []byte
143		op := durableAuditIndexOperation(args)
144		err := lockmetrics.Instrument("index.lock", op, func() error {
145			var lastErr error
146			var lastDiag string
147			for attempt := 0; attempt < gitlock.RecoveryAttempts; attempt++ {
148				out, lastErr = runDurableAuditGit(gitDir, args...)
149				if lastErr == nil {
150					return nil
151				}
152				if !gitlock.IsTransientGitContention(string(out), lastErr) {
153					return lastErr
154				}
155				result, recErr := gitlock.RecoverGitIndexLock(gitDir)
156				if recErr != nil {
157					return fmt.Errorf("%s; index-lock recovery failed: %w", strings.TrimSpace(string(out)), recErr)
158				}
159				lastDiag = result.Reason
160				if !result.Removed {
161					time.Sleep(gitlock.LiveOwnerWait)
162				}
163			}
164			return fmt.Errorf("%s; index-lock recovery exhausted after %d attempts: %s", strings.TrimSpace(string(out)), gitlock.RecoveryAttempts, lastDiag)
165		})
166		return out, err
167	}
168	
169	func durableAuditIndexOperation(args []string) string {
170		if len(args) == 0 {
171			return "index"
172		}
173		return "index." + args[0]
174	}
