176	func dirtyDurableAuditPaths(statusOutput string) []string {
177		lines := strings.Split(statusOutput, "\n")
178		seen := make(map[string]struct{}, len(lines))
179		paths := make([]string, 0, len(lines))
180		for _, line := range lines {
181			if len(line) < 4 {
182				continue
183			}
184			path := strings.TrimSpace(line[3:])
185			if arrow := strings.LastIndex(path, " -> "); arrow >= 0 {
186				path = strings.TrimSpace(path[arrow+4:])
187			}
188			if path == "" {
189				continue
190			}
191			if _, ok := seen[path]; ok {
192				continue
193			}
194			seen[path] = struct{}{}
195			paths = append(paths, path)
196		}
197		return paths
198	}
