200	func durableAuditCommitMessage(attemptID string) string {
201		id := strings.TrimSpace(attemptID)
202		if id == "" {
203			id = time.Now().UTC().Format("20060102T150405")
204		}
205		return fmt.Sprintf("chore: update tracker (execute-bead %s)", id)
206	}
