21	// IsManagedTrackerPath reports whether path is one of the DDx-managed tracker
22	// files or lives under the managed attachments directory.
23	func IsManagedTrackerPath(path string) bool {
24		clean := strings.TrimSpace(filepath.ToSlash(path))
25		if clean == "" {
26			return false
27		}
28		for _, managed := range managedPathspecs {
29			root := strings.TrimSuffix(filepath.ToSlash(managed), "/")
30			if clean == root || strings.HasPrefix(clean, root+"/") {
31				return true
32			}
33		}
34		return false
35	}
